// src/components/tools/ToolBox.tsx

import React, { useEffect, useRef } from 'react';
import { useMusic } from '../../context/MusicContext';
import { useMetronome } from '../../hooks/useMetronome';
import { useTuner } from '../../hooks/useTuner';

const ToolBox: React.FC = () => {
  const { 
    bpm, setBpm, isPlaying, togglePlay, 
    timeSignature, setTimeSignature 
  } = useMusic();
  
  useMetronome(bpm, timeSignature);
  
  const { 
    isActive: isTunerActive, 
    startTuner, 
    stopTuner, 
    note: tunerNote, 
    cents, 
    frequency,
    getAudioData
  } = useTuner();

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number | null>(null);

  const TIME_SIGNATURES = [
    { beats: 4, noteValue: 4, label: '4/4' },
    { beats: 3, noteValue: 4, label: '3/4' },
    { beats: 2, noteValue: 4, label: '2/4' },
    { beats: 6, noteValue: 8, label: '6/8' },
    { beats: 5, noteValue: 4, label: '5/4' },
    { beats: 7, noteValue: 4, label: '7/4' },
    { beats: 12, noteValue: 8, label: '12/8' },
  ];

  const getTunerColor = () => {
    if (!isTunerActive) return 'var(--text-muted)';
    const absCents = Math.abs(cents);
    if (absCents < 3) return '#4ade80';
    if (absCents < 10) return '#fbbf24';
    if (absCents < 20) return '#fb923c';
    return '#f87171';
  };

  const isInTune = isTunerActive && Math.abs(cents) < 3 && tunerNote && tunerNote !== '-' && tunerNote !== '...';
  const tunerColor = getTunerColor();

  const formatCents = (centsValue: number) => {
    if (centsValue === 0) return '0¢';
    const sign = centsValue > 0 ? '♯' : '♭';
    return `${sign} ${Math.abs(centsValue)}¢`;
  };

  const drawWaveform = (dataArray: Float32Array | null) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    
    const width = canvas.width;
    const height = canvas.height;
    
    ctx.clearRect(0, 0, width, height);
    
    const gradient = ctx.createLinearGradient(0, 0, 0, height);
    gradient.addColorStop(0, 'rgba(0,0,0,0.2)');
    gradient.addColorStop(0.5, 'rgba(0,0,0,0)');
    gradient.addColorStop(1, 'rgba(0,0,0,0.2)');
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, width, height);
    
    if (!dataArray || !isTunerActive) {
      ctx.strokeStyle = 'rgba(255,255,255,0.1)';
      ctx.lineWidth = 2;
      ctx.setLineDash([5, 5]);
      ctx.beginPath();
      ctx.moveTo(0, height / 2);
      ctx.lineTo(width, height / 2);
      ctx.stroke();
      ctx.setLineDash([]);
      return;
    }
    
    ctx.strokeStyle = 'rgba(255,255,255,0.03)';
    ctx.lineWidth = 1;
    for (let i = 0; i < 5; i++) {
      const y = (height / 5) * i;
      ctx.beginPath();
      ctx.moveTo(0, y);
      ctx.lineTo(width, y);
      ctx.stroke();
    }
    
    ctx.strokeStyle = 'rgba(255,255,255,0.1)';
    ctx.lineWidth = 1;
    ctx.setLineDash([3, 3]);
    ctx.beginPath();
    ctx.moveTo(0, height / 2);
    ctx.lineTo(width, height / 2);
    ctx.stroke();
    ctx.setLineDash([]);
    
    const step = Math.floor(dataArray.length / width);
    const midY = height / 2;
    
    const waveGradient = ctx.createLinearGradient(0, 0, 0, height);
    const color = isInTune ? '#4ade80' : tunerColor;
    waveGradient.addColorStop(0, color + '40');
    waveGradient.addColorStop(0.5, color);
    waveGradient.addColorStop(1, color + '40');
    
    ctx.strokeStyle = waveGradient;
    ctx.lineWidth = 2;
    ctx.shadowColor = color;
    ctx.shadowBlur = 10;
    ctx.beginPath();
    
    for (let i = 0; i < width; i++) {
      const index = Math.floor(i * step);
      const value = dataArray[index] || 0;
      const y = midY + value * (height / 2.5);
      
      if (i === 0) {
        ctx.moveTo(i, y);
      } else {
        ctx.lineTo(i, y);
      }
    }
    ctx.stroke();
    ctx.shadowBlur = 0;
    
    const fillGradient = ctx.createLinearGradient(0, 0, 0, height);
    fillGradient.addColorStop(0, color + '20');
    fillGradient.addColorStop(0.5, color + '10');
    fillGradient.addColorStop(1, color + '00');
    
    ctx.fillStyle = fillGradient;
    ctx.beginPath();
    
    for (let i = 0; i < width; i++) {
      const index = Math.floor(i * step);
      const value = dataArray[index] || 0;
      const y = midY + value * (height / 2.5);
      
      if (i === 0) {
        ctx.moveTo(i, y);
      } else {
        ctx.lineTo(i, y);
      }
    }
    ctx.lineTo(width, height);
    ctx.lineTo(0, height);
    ctx.closePath();
    ctx.fill();
    
    ctx.strokeStyle = color + '80';
    ctx.lineWidth = 1;
    for (let i = 0; i < width; i += 20) {
      const index = Math.floor(i * step);
      const value = dataArray[index] || 0;
      const y = midY + value * (height / 2.5);
      
      ctx.beginPath();
      ctx.moveTo(i, midY);
      ctx.lineTo(i, y);
      ctx.stroke();
    }
  };

  useEffect(() => {
    if (!isTunerActive) {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
        animationRef.current = null;
      }
      drawWaveform(null);
      return;
    }

    const animate = () => {
      const data = getAudioData();
      if (data) {
        drawWaveform(data);
      }
      animationRef.current = requestAnimationFrame(animate);
    };

    animate();

    return () => {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
        animationRef.current = null;
      }
    };
  }, [isTunerActive, getAudioData]);

  useEffect(() => {
    const handleKeyPress = (e: KeyboardEvent) => {
      if (e.code === 'Space' && !e.repeat) {
        e.preventDefault();
        togglePlay();
      }
      if (e.code === 'KeyT' && !e.repeat) {
        e.preventDefault();
        isTunerActive ? stopTuner() : startTuner();
      }
    };

    window.addEventListener('keydown', handleKeyPress);
    return () => window.removeEventListener('keydown', handleKeyPress);
  }, [togglePlay, isTunerActive, startTuner, stopTuner]);

  return (
    <div style={{ 
      background: 'var(--bg-panel)', 
      borderRadius: 'var(--radius)', 
      border: '1px solid var(--border-color)', 
      padding: '20px', 
      display: 'flex', 
      flexDirection: 'column', 
      gap: '16px',
      flexShrink: 0,
      minWidth: '200px'
    }}>
      
      <div style={{ 
        fontSize: '11px', 
        color: 'var(--text-muted)', 
        fontWeight: 800, 
        textTransform: 'uppercase', 
        letterSpacing: '1px',
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center'
      }}>
        <span>🎛️ Control Center</span>
        <span style={{ 
          fontSize: '8px', 
          opacity: 0.5,
          background: 'var(--bg-secondary)',
          padding: '2px 8px',
          borderRadius: '4px'
        }}>
          SPACE · T
        </span>
      </div>

      {/* МЕТРОНОМ */}
      <div style={{ 
        display: 'flex', 
        flexDirection: 'column', 
        gap: '8px',
        background: 'var(--bg-root)', 
        padding: '10px 14px', 
        borderRadius: '10px', 
        border: `1px solid ${isPlaying ? 'var(--accent)' : 'var(--border-color)'}`,
        transition: 'border-color 0.3s',
        boxShadow: isPlaying ? '0 0 20px rgba(0,255,157,0.05)' : 'none'
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1px' }}>
            <span style={{ fontSize: '9px', color: 'var(--text-muted)', fontWeight: 800, letterSpacing: '0.5px' }}>TEMPO</span>
            <span style={{ fontSize: '12px', color: 'var(--text-primary)', fontWeight: 900 }}>BPM</span>
          </div>
          
          <input 
            type="number" 
            value={bpm} 
            onChange={(e) => {
              const val = Number(e.target.value);
              if (val >= 20 && val <= 300) setBpm(val);
            }}
            style={{ 
              width: '60px', 
              background: 'var(--bg-secondary)', 
              border: '1px solid var(--border-color)', 
              borderRadius: '6px',
              color: 'var(--text-primary)', 
              fontWeight: 900, 
              fontSize: '16px', 
              outline: 'none', 
              textAlign: 'center',
              padding: '4px 0'
            }} 
            min="20"
            max="300"
          />
          
          <button 
            onClick={togglePlay} 
            style={{ 
              marginLeft: 'auto', 
              width: '36px', 
              height: '36px', 
              borderRadius: '50%', 
              background: isPlaying ? 'var(--accent)' : 'var(--bg-secondary)', 
              color: isPlaying ? '#000' : 'var(--accent)', 
              border: `2px solid var(--accent)`, 
              cursor: 'pointer', 
              display: 'flex', 
              alignItems: 'center', 
              justifyContent: 'center',
              fontWeight: 900,
              fontSize: '14px',
              transition: 'all 0.2s',
              boxShadow: isPlaying ? '0 0 12px var(--accent)' : 'none',
              transform: isPlaying ? 'scale(1.05)' : 'scale(1)'
            }}
            title="Space"
          >
            {isPlaying ? '■' : '▶'}
          </button>
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          <span style={{ fontSize: '9px', color: 'var(--text-muted)', fontWeight: 700, letterSpacing: '0.5px' }}>
            TIME
          </span>
          <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap' }}>
            {TIME_SIGNATURES.map(sig => (
              <button
                key={sig.label}
                onClick={() => setTimeSignature({ beats: sig.beats, noteValue: sig.noteValue })}
                style={{
                  background: timeSignature.beats === sig.beats && timeSignature.noteValue === sig.noteValue 
                    ? 'var(--accent)' 
                    : 'var(--bg-secondary)',
                  color: timeSignature.beats === sig.beats && timeSignature.noteValue === sig.noteValue 
                    ? '#000' 
                    : 'var(--text-muted)',
                  border: 'none',
                  padding: '2px 8px',
                  borderRadius: '4px',
                  fontSize: '10px',
                  fontWeight: 700,
                  cursor: 'pointer',
                  transition: 'all 0.2s',
                  fontFamily: 'monospace'
                }}
                onMouseEnter={e => {
                  if (!(timeSignature.beats === sig.beats && timeSignature.noteValue === sig.noteValue)) {
                    e.currentTarget.style.color = 'var(--text-primary)';
                    e.currentTarget.style.background = 'var(--bg-hover)';
                  }
                }}
                onMouseLeave={e => {
                  if (!(timeSignature.beats === sig.beats && timeSignature.noteValue === sig.noteValue)) {
                    e.currentTarget.style.color = 'var(--text-muted)';
                    e.currentTarget.style.background = 'var(--bg-secondary)';
                  }
                }}
              >
                {sig.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* 🔥 ТЮНЕР */}
      <div style={{ 
        background: 'var(--bg-root)', 
        padding: '14px', 
        borderRadius: '10px', 
        border: `1px solid ${isTunerActive ? 'var(--accent)' : 'var(--border-color)'}`,
        boxShadow: isTunerActive ? '0 0 20px rgba(0,255,157,0.05)' : 'none',
        transition: 'all 0.3s'
      }}>
        
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '10px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <span style={{ fontSize: '14px' }}>🎙️</span>
            <span style={{ fontSize: '10px', color: 'var(--text-muted)', fontWeight: 800, letterSpacing: '0.5px' }}>TUNER</span>
            {isTunerActive && (
              <span style={{ 
                fontSize: '8px', 
                color: 'var(--accent)',
                fontWeight: 700,
                background: 'rgba(0,255,157,0.1)',
                padding: '2px 8px',
                borderRadius: '8px',
                animation: 'pulse 1.5s infinite'
              }}>
                🎵 ACTIVE
              </span>
            )}
          </div>
          
          <button 
            onClick={isTunerActive ? stopTuner : startTuner}
            style={{
              background: isTunerActive ? 'var(--accent)' : 'transparent',
              color: isTunerActive ? '#000' : 'var(--text-muted)',
              border: `1px solid ${isTunerActive ? 'var(--accent)' : 'var(--border-color)'}`,
              padding: '2px 14px', 
              borderRadius: '12px', 
              fontSize: '9px', 
              fontWeight: 900, 
              cursor: 'pointer', 
              transition: '0.2s',
              boxShadow: isTunerActive ? '0 0 12px rgba(0,255,157,0.3)' : 'none'
            }}
            title="Press T"
          >
            {isTunerActive ? 'ON' : 'OFF'}
          </button>
        </div>

        {isTunerActive ? (
          <div style={{ textAlign: 'center', position: 'relative' }}>
            <canvas 
              ref={canvasRef}
              width={300}
              height={80}
              style={{
                width: '100%',
                height: '80px',
                background: 'rgba(0,0,0,0.3)',
                borderRadius: '8px',
                marginBottom: '12px',
                display: 'block'
              }}
            />
            
            <div style={{ 
              fontSize: '40px', 
              fontWeight: 900, 
              color: tunerColor, 
              lineHeight: 1, 
              textShadow: isInTune ? `0 0 30px ${tunerColor}` : 'none',
              transition: 'color 0.1s, text-shadow 0.3s',
              letterSpacing: '2px',
              fontFamily: 'monospace'
            }}>
              {tunerNote || '-'}
            </div>
            
            <div style={{ display: 'flex', justifyContent: 'center', gap: '16px', marginTop: '2px' }}>
              <span style={{ fontSize: '11px', color: 'var(--text-muted)', fontWeight: 600 }}>
                {frequency > 0 ? `${frequency.toFixed(1)} Hz` : '—'}
              </span>
              <span style={{ 
                fontSize: '11px', 
                color: isInTune ? '#4ade80' : 'var(--text-muted)',
                fontWeight: 700
              }}>
                {isInTune ? '✓ IN TUNE' : (tunerNote && tunerNote !== '-' && tunerNote !== '...' ? formatCents(cents) : '—')}
              </span>
            </div>

            <div style={{ 
              width: '100%', 
              height: '28px', 
              background: 'var(--bg-secondary)', 
              marginTop: '10px', 
              borderRadius: '4px', 
              position: 'relative', 
              overflow: 'hidden',
              boxShadow: 'inset 0 2px 8px rgba(0,0,0,0.4)'
            }}>
              <div style={{ 
                position: 'absolute', 
                top: 0, 
                bottom: 0, 
                width: '2px', 
                background: 'var(--text-muted)', 
                left: '50%', 
                transform: 'translateX(-50%)', 
                zIndex: 2,
                opacity: 0.3
              }} />
              
              <div style={{
                position: 'absolute',
                top: 0,
                bottom: 0,
                left: '10%',
                right: '10%',
                background: `linear-gradient(to right, #f87171, #fb923c, #fbbf24, #4ade80, #4ade80, #fbbf24, #fb923c, #f87171)`,
                opacity: 0.12,
                borderRadius: '4px'
              }} />

              {tunerNote && tunerNote !== '-' && tunerNote !== '...' && (
                <div style={{ 
                  position: 'absolute', 
                  top: '2px', 
                  bottom: '2px',
                  width: '4px', 
                  borderRadius: '2px',
                  background: tunerColor,
                  left: `calc(50% + ${Math.max(-80, Math.min(80, cents))}%)`, 
                  transform: 'translateX(-50%)', 
                  transition: 'left 0.05s linear, background 0.1s',
                  zIndex: 3,
                  boxShadow: `0 0 12px ${tunerColor}`
                }} />
              )}

              {isInTune && (
                <div style={{
                  position: 'absolute',
                  top: '50%',
                  left: '50%',
                  transform: 'translate(-50%, -50%)',
                  fontSize: '9px',
                  fontWeight: 900,
                  color: '#4ade80',
                  letterSpacing: '1px',
                  textShadow: '0 0 20px rgba(74, 222, 128, 0.5)',
                  zIndex: 4,
                  background: 'rgba(0,0,0,0.7)',
                  padding: '0 12px',
                  borderRadius: '2px'
                }}>
                  ✓ TUNE
                </div>
              )}
            </div>

            <div style={{ 
              width: '100%', 
              height: '3px', 
              background: 'var(--bg-secondary)', 
              marginTop: '6px', 
              borderRadius: '2px',
              overflow: 'hidden'
            }}>
              <div style={{
                width: `${Math.min(100, Math.max(10, Math.abs(cents) * 2))}%`,
                height: '100%',
                background: `linear-gradient(to right, ${tunerColor}, ${isInTune ? '#4ade80' : tunerColor})`,
                transition: 'width 0.1s',
                borderRadius: '2px'
              }} />
            </div>
          </div>
        ) : (
          <div style={{ textAlign: 'center', color: 'var(--text-muted)', fontSize: '11px', padding: '20px 0', opacity: 0.5 }}>
            <span style={{ fontSize: '28px', display: 'block', marginBottom: '8px' }}>🎙️</span>
            Click <strong style={{ color: 'var(--accent)' }}>ON</strong> or press <strong style={{ color: 'var(--accent)' }}>T</strong> to tune
          </div>
        )}
      </div>

      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.4; }
        }
      `}</style>
    </div>
  );
};

export default ToolBox;