// src/components/fretboard/Tablature.tsx

import React, { useState, useEffect } from 'react';
import { useMusic } from '../../context/MusicContext';
import { generateSmartLick, type Lick, type LickNote } from '../../services/AIEngine';
import { generateTips, type Tip } from '../../utils/tipsGenerator';
import TablatureDisplay from './TablatureDisplay';

interface TablatureProps {
  compact?: boolean;
}

const Tablature: React.FC<TablatureProps> = ({ compact = false }) => {
  const { mode, keyNote, getScaleNotes, bpm, timeSignature } = useMusic();
  const [isGenerating, setIsGenerating] = useState(false);
  const [isPlayingAudio, setIsPlayingAudio] = useState(false);
  const [currentLick, setCurrentLick] = useState<Lick | null>(null);
  const [localActiveStep, setLocalActiveStep] = useState<number>(-1);
  const [playbackSpeed, setPlaybackSpeed] = useState(1.0);
  const [tips, setTips] = useState<Tip[]>([]);
  const [audioContext, setAudioContext] = useState<AudioContext | null>(null);
  const [scheduledTimeouts, setScheduledTimeouts] = useState<number[]>([]);
  const [scheduledOscillators, setScheduledOscillators] = useState<any[]>([]);

  // Генерация лика при изменении параметров
  useEffect(() => {
    const scale = getScaleNotes();
    const safeScale = scale && scale.length > 0 ? scale : ['C', 'D', 'E', 'F', 'G', 'A', 'B'];
    const safeKey = keyNote || 'C';
    const safeMode = mode || 'major';
    const newLick = generateSmartLick(
      safeScale, 
      safeKey, 
      safeMode, 
      bpm || 120, 
      timeSignature || { beats: 4, noteValue: 4 }
    );
    setCurrentLick(newLick);
    generateLickTips(newLick, safeKey, safeMode);
  }, [keyNote, mode, bpm, timeSignature, getScaleNotes]);

  // Генерация советов для лика
  const generateLickTips = (lick: Lick, key: string, mode: string) => {
    try {
      const chordProgression = ['I', 'IV', 'V'];
      const generatedTips = generateTips(
        lick,
        key,
        mode,
        chordProgression,
        bpm || 120
      );
      setTips(generatedTips);
    } catch (err) {
      console.error("Ошибка генерации советов:", err);
      setTips([]);
    }
  };

  // Генерация нового лика
  const handleGenerate = () => {
    if (isPlayingAudio) {
      stopPlayback();
    }
    setIsGenerating(true);
    const scale = getScaleNotes();
    const safeScale = scale && scale.length > 0 ? scale : ['C', 'D', 'E', 'F', 'G', 'A', 'B'];
    setTimeout(() => {
      const newLick = generateSmartLick(
        safeScale, 
        keyNote || 'C', 
        mode || 'major', 
        bpm || 120, 
        timeSignature || { beats: 4, noteValue: 4 }
      );
      setCurrentLick(newLick);
      generateLickTips(newLick, keyNote || 'C', mode || 'major');
      setIsGenerating(false);
      setLocalActiveStep(-1);
    }, 400);
  };

  // ОСТАНОВКА ВОСПРОИЗВЕДЕНИЯ
  const stopPlayback = () => {
    // Останавливаем все запланированные таймауты
    scheduledTimeouts.forEach(timeoutId => {
      clearTimeout(timeoutId);
    });
    setScheduledTimeouts([]);

    // Останавливаем все осцилляторы
    scheduledOscillators.forEach(osc => {
      try {
        osc.stop();
        osc.disconnect();
      } catch (e) {}
    });
    setScheduledOscillators([]);

    // Закрываем AudioContext
    if (audioContext && audioContext.state !== 'closed') {
      audioContext.close();
      setAudioContext(null);
    }

    setIsPlayingAudio(false);
    setLocalActiveStep(-1);
  };

  // Воспроизведение аудио
  const playLickAudio = () => {
    if (!currentLick || isPlayingAudio) return;
    
    // Если уже играет - останавливаем
    if (isPlayingAudio) {
      stopPlayback();
      return;
    }

    // Создаем новый AudioContext
    const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
    const ctx = new AudioContextClass();
    setAudioContext(ctx);
    
    setIsPlayingAudio(true);
    setLocalActiveStep(-1);

    try {
      const OPEN_FREQS = [329.63, 246.94, 196.00, 146.83, 110.00, 82.41];
      
      let startTime = ctx.currentTime + 0.1;
      const currentBpm = (bpm || 120) * playbackSpeed;
      const quarterDuration = 60 / currentBpm;
      
      const timeouts: number[] = [];
      const oscillators: any[] = [];

      currentLick.notes.forEach((note: LickNote, index: number) => {
        if (note.isRest) {
          const restDuration = note.duration === 'quarter' ? quarterDuration : quarterDuration / 2;
          startTime += restDuration;
          return;
        }

        const fretValue = note.fret ?? 0;
        const freq = OPEN_FREQS[note.string] * Math.pow(2, fretValue / 12);
        
        const durationMap: Record<string, number> = {
          'whole': 4,
          'half': 2,
          'quarter': 1,
          'eighth': 0.5,
          'sixteenth': 0.25,
          'dotted_eighth': 0.75
        };
        let noteDuration = quarterDuration * (durationMap[note.duration || 'eighth'] || 1);
        const humanFactor = note.durationFactor || (0.9 + Math.random() * 0.2);
        const actualDuration = noteDuration * humanFactor;

        const accentFactor = note.accent ? 1.2 : (note.velocity || 0.7);

        // Подсветка текущей ноты
        const timeoutId = setTimeout(() => {
          setLocalActiveStep(index);
        }, (startTime - ctx.currentTime) * 1000);
        timeouts.push(timeoutId);

        const osc = ctx.createOscillator();
        const gainNode = ctx.createGain();

        if (note.technique === 'hammer' || note.technique === 'pull') {
          osc.type = 'sine';
        } else if (note.technique === 'ghost') {
          osc.type = 'sine';
        } else if (note.technique === 'choke') {
          osc.type = 'sawtooth';
        } else {
          osc.type = 'triangle';
        }
        
        osc.frequency.setValueAtTime(freq, startTime);

        // Вибрато
        if (note.technique === 'vibrato') {
          const lfo = ctx.createOscillator();
          const lfoGain = ctx.createGain();
          lfo.type = 'sine';
          lfo.frequency.value = 5 + Math.random() * 2;
          lfoGain.gain.value = freq * (0.01 + Math.random() * 0.02);
          lfo.connect(lfoGain);
          lfoGain.connect(osc.frequency);
          lfo.start(startTime);
          lfo.stop(startTime + actualDuration);
          oscillators.push(lfo);
        }

        // Бенд
        if (note.technique === 'bend' || note.technique === 'prebend') {
          const bendAmount = (note as any).bendAmount || 1;
          const bendStart = note.technique === 'prebend' ? startTime : startTime + actualDuration * 0.3;
          osc.frequency.setValueAtTime(freq, bendStart);
          osc.frequency.exponentialRampToValueAtTime(
            freq * Math.pow(2, bendAmount / 12),
            bendStart + actualDuration * 0.2
          );
        }

        // Форшлаг
        if ((note as any).graceNote && !note.isRest) {
          const graceNote = (note as any).graceNote;
          const graceFreq = OPEN_FREQS[graceNote.string] * Math.pow(2, graceNote.fret / 12);
          const graceOsc = ctx.createOscillator();
          const graceGain = ctx.createGain();
          graceOsc.type = 'sine';
          graceOsc.frequency.value = graceFreq;
          graceGain.gain.setValueAtTime(0.1, startTime - 0.05);
          graceGain.gain.exponentialRampToValueAtTime(0.001, startTime);
          graceOsc.connect(graceGain);
          graceGain.connect(ctx.destination);
          graceOsc.start(startTime - 0.05);
          graceOsc.stop(startTime);
          oscillators.push(graceOsc);
        }

        // Громкость
        let attackTime = 0.008 + Math.random() * 0.01;
        let sustainLevel = 0.8 * accentFactor;

        if (note.technique === 'hammer') {
          attackTime = 0.005;
          sustainLevel = 0.6 * accentFactor;
        } else if (note.technique === 'pull') {
          attackTime = 0.005;
          sustainLevel = 0.55 * accentFactor;
        }

        gainNode.gain.setValueAtTime(0, startTime);
        gainNode.gain.linearRampToValueAtTime(sustainLevel, startTime + attackTime);
        gainNode.gain.exponentialRampToValueAtTime(sustainLevel * 0.6, startTime + actualDuration * 0.1);
        gainNode.gain.exponentialRampToValueAtTime(0.001, startTime + actualDuration);

        osc.connect(gainNode);
        gainNode.connect(ctx.destination);
        osc.start(startTime);
        osc.stop(startTime + actualDuration + 0.1);
        oscillators.push(osc);

        startTime += actualDuration;
      });

      // Сохраняем все таймауты и осцилляторы для остановки
      setScheduledTimeouts(timeouts);
      setScheduledOscillators(oscillators);

      // Автоматическая остановка после окончания воспроизведения
      const totalDuration = (startTime - ctx.currentTime) * 1000 + 500;
      const stopTimeout = setTimeout(() => {
        stopPlayback();
      }, totalDuration);
      timeouts.push(stopTimeout);

    } catch (e) {
      console.error("Audio Synthesis Failed:", e);
      stopPlayback();
    }
  };

  // Очистка при размонтировании
  useEffect(() => {
    return () => {
      stopPlayback();
    };
  }, []);

  return (
    <div style={{ 
      background: 'var(--bg-panel)', 
      borderRadius: 'var(--radius)', 
      border: '1px solid var(--border-color)', 
      boxShadow: '0 8px 24px rgba(0,0,0,0.2)', 
      display: 'flex', 
      flexDirection: 'column', 
      overflow: 'hidden', 
      flexShrink: 0, 
      minHeight: compact ? '200px' : '310px', 
      marginTop: compact ? '0' : '8px' 
    }}>
      
      <div style={{ 
        padding: compact ? '8px 16px' : '16px 24px', 
        background: 'var(--bg-primary)', 
        borderBottom: '1px solid var(--border-color)', 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center', 
        flexWrap: 'wrap', 
        gap: '8px' 
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <span style={{ 
            fontSize: compact ? '9px' : '11px', 
            color: 'var(--text-muted)', 
            fontWeight: 800, 
            textTransform: 'uppercase', 
            letterSpacing: '1px' 
          }}>
            🎸 Lick Generator
          </span>
          <span style={{ fontSize: compact ? '12px' : '14px', fontWeight: 800, color: 'var(--accent)' }}>
            {currentLick ? currentLick.name : 'Initializing...'}
          </span>
          {currentLick && !compact && (
            <span style={{ 
              fontSize: '11px', 
              color: 'var(--text-muted)', 
              fontWeight: 600, 
              background: 'var(--bg-secondary)', 
              padding: '2px 10px', 
              borderRadius: '12px' 
            }}>
              {timeSignature.beats}/{timeSignature.noteValue}
            </span>
          )}
        </div>
        
        {!compact && (
          <div style={{ display: 'flex', gap: '12px', alignItems: 'center', flexWrap: 'wrap' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
              <span style={{ fontSize: '9px', color: 'var(--text-muted)', fontWeight: 700 }}>SPEED</span>
              <input 
                type="range" 
                min="0.5" 
                max="2.0" 
                step="0.1" 
                value={playbackSpeed}
                onChange={(e) => setPlaybackSpeed(parseFloat(e.target.value))}
                style={{ width: '60px', height: '4px', accentColor: 'var(--accent)', cursor: 'pointer' }}
              />
              <span style={{ fontSize: '11px', color: 'var(--accent)', fontWeight: 700, minWidth: '30px' }}>
                {playbackSpeed.toFixed(1)}x
              </span>
            </div>

            {/* КНОПКА PLAY/STOP */}
            <button 
              onClick={isPlayingAudio ? stopPlayback : playLickAudio}
              disabled={isGenerating || !currentLick}
              style={{ 
                background: isPlayingAudio ? '#ff4444' : 'var(--accent)', 
                color: isPlayingAudio ? '#fff' : '#000', 
                border: isPlayingAudio ? `2px solid #ff4444` : 'none', 
                padding: '6px 20px', 
                borderRadius: '20px', 
                fontWeight: 900, 
                fontSize: '12px', 
                cursor: (isGenerating || !currentLick) ? 'default' : 'pointer', 
                transition: '0.2s', 
                display: 'flex', 
                gap: '8px', 
                alignItems: 'center', 
                opacity: (isGenerating || !currentLick) ? 0.5 : 1,
                minWidth: '80px',
                justifyContent: 'center'
              }}
            >
              {isPlayingAudio ? '⏹ STOP' : '🔊 PLAY'}
            </button>

            <button 
              onClick={handleGenerate}
              disabled={isGenerating || isPlayingAudio}
              style={{ 
                background: 'var(--bg-secondary)', 
                color: 'var(--text-primary)', 
                border: '1px solid var(--border-color)', 
                padding: '6px 16px', 
                borderRadius: '20px', 
                fontWeight: 800, 
                fontSize: '12px', 
                cursor: 'pointer', 
                transition: '0.2s', 
                display: 'flex', 
                gap: '8px', 
                alignItems: 'center', 
                opacity: isPlayingAudio ? 0.5 : 1 
              }}
              onMouseEnter={e => { if(!isPlayingAudio) e.currentTarget.style.borderColor = 'var(--accent)'; }}
              onMouseLeave={e => e.currentTarget.style.borderColor = 'var(--border-color)'}
            >
              {isGenerating ? '⏳ GENERATING...' : '🎲 GENERATE NEW'}
            </button>
          </div>
        )}
      </div>

      <div style={{ 
        padding: compact ? '8px' : '24px', 
        overflowX: 'auto', 
        background: '#111216', 
        flex: 1, 
        display: 'flex', 
        alignItems: 'center', 
        justifyContent: 'flex-start' 
      }}>
        {!currentLick ? (
          <div style={{ 
            color: 'var(--text-muted)', 
            fontWeight: 800, 
            fontSize: '12px', 
            letterSpacing: '1px', 
            width: '100%', 
            textAlign: 'center' 
          }}>
            ⏳ LOADING...
          </div>
        ) : (
          <TablatureDisplay
            notes={currentLick.notes}
            activeStep={localActiveStep}
            isGenerating={isGenerating}
            compact={compact}
            noteSpacing={compact ? 50 : 70}
            height={compact ? 120 : 180}
          />
        )}
      </div>

      {tips && tips.length > 0 && !compact && (
        <div style={{ 
          padding: '16px 24px',
          borderTop: '1px solid var(--border-color)',
          background: 'var(--bg-primary)'
        }}>
          <div style={{ 
            fontSize: '11px', 
            color: 'var(--text-muted)', 
            fontWeight: 700,
            textTransform: 'uppercase',
            letterSpacing: '1px',
            marginBottom: '8px'
          }}>
            💡 AI Tips
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
            {tips.map((tip, index) => (
              <div key={index} style={{
                fontSize: '12px',
                color: 'var(--text-primary)',
                padding: '6px 12px',
                background: 'rgba(0,255,157,0.05)',
                borderRadius: '6px',
                borderLeft: `3px solid ${tip.category === 'harmony' ? '#ff6b6b' : tip.category === 'technique' ? '#ffb800' : '#00b8ff'}`
              }}>
                <span style={{ marginRight: '8px' }}>{tip.icon || '💡'}</span>
                {tip.title && <strong>{tip.title}: </strong>}
                {tip.description}
                {tip.actionable && (
                  <div style={{ fontSize: '11px', color: 'var(--accent)', marginTop: '4px' }}>
                    💡 {tip.actionable}
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default Tablature;